            #                 "leverage": "0.0",
            #                 "type": "LIQUID_LONG",
            #                 "side": null,
            #                 "closeSize": null,
            #                 "pnl": "-1.0000003793999999",
            #                 "realisedGrossCost": "0.9993849748999999",
